{"path":"/tmp/isolated_workspace_1091/vector_store.py","content":"import os
import hashlib
import math
from typing import List, Dict, Any

import chromadb
from chromadb.config import Settings
from openai import OpenAI
from tqdm import tqdm

from config import (
    VECTOR_DB_PATH,
    COLLECTION_NAME,
    OPENAI_API_KEY,
    OPENAI_API_BASE,
    OPENAI_EMBEDDING_MODEL,
    TOP_K,
)


class VectorStore:

    def __init__(
        self,
        db_path: str = VECTOR_DB_PATH,
        collection_name: str = COLLECTION_NAME,
        api_key: str = OPENAI_API_KEY,
        api_base: str = OPENAI_API_BASE,
    ):
        self.db_path = db_path
        self.collection_name = collection_name

        # 初始化OpenAI客户端（允许无 key）
        self.client = OpenAI(api_key=api_key or None, base_url=api_base or None)
        disable_emb = os.getenv("DISABLE_OPENAI_EMBEDDINGS", "0") == "1"
        # SII 接口通常不提供 embedding，检测到 SII base 时默认禁用
        if (api_base or "").find("opensii") >= 0:
            disable_emb = True
        self.use_openai = bool(api_key) and (not disable_emb)
        self._openai_disabled = False
        self.use_local_embedding = os.getenv("USE_LOCAL_EMBEDDING", "0") == "1"
        self._local_embedder = None

        # 初始化ChromaDB
        os.makedirs(db_path, exist_ok=True)
        self.chroma_client = chromadb.PersistentClient(
            path=db_path, settings=Settings(anonymized_telemetry=False)
        )

        # 获取或创建collection
        self.collection = self.chroma_client.get_or_create_collection(
            name=collection_name, metadata={"description": "课程材料向量数据库"}
        )

    def _get_local_embedder(self):
        if self._local_embedder is None:
            from sentence_transformers import SentenceTransformer

            model_name = os.getenv(
                "LOCAL_EMBEDDING_MODEL",
                "sentence-transformers/paraphrase-multilingual-MiniLM-L12-v2",
            )
            self._local_embedder = SentenceTransformer(model_name)
        return self._local_embedder

    def get_embedding(self, text: str) -> List[float]:
        """获取文本的向量表示

        优先使用 OpenAI embedding；若不可用，可选择本地 embedding；
        若仍不可用，则回退为确定性的哈希向量，保证流程可运行。
        """
        text = (text or "").strip()
        if not text:
            return []

        # 1) OpenAI 优先（如有 key）
        if self.use_openai and (not self._openai_disabled):
            try:
                resp = self.client.with_options(timeout=30.0).embeddings.create(
                    model=OPENAI_EMBEDDING_MODEL, input=text
                )
                vec = resp.data[0].embedding
                if vec:
                    return list(vec)
            except Exception as e:
                self._openai_disabled = True
                print(f"OpenAI 嵌入失败，已禁用后续 OpenAI 嵌入: {e}")

        # 2) 可选本地模型
        if self.use_local_embedding:
            try:
                embedder = self._get_local_embedder()
                vec = embedder.encode([text], normalize_embeddings=True)[0]
                return [float(x) for x in vec]
            except Exception as e:
                print(f"本地嵌入失败，回退哈希: {e}")

        # 3) 快速哈希向量（保证流程不阻塞）
        # 使用 token 级哈希累加，避免整段文本单次 sha256 带来的检索失真
        dim = 256
        arr = [0.0] * dim
        tokens = text.split()
        if not tokens:
            tokens = [text[i : i + 4] for i in range(0, len(text), 4)]

        for token in tokens:
            h = hashlib.sha256(token.encode("utf-8")).digest()
            for i in range(dim):
                arr[i] += h[i % len(h)] / 255.0 - 0.5

        norm = math.sqrt(sum(x * x for x in arr)) or 1.0
        return [float(x / norm) for x in arr]

    def add_documents(self, chunks: List[Dict[str, str]]) -> None:
        """添加文档块到向量数据库"""
        if not chunks:
            print("无文档块可添加")
            return

        ids: List[str] = []
        documents: List[str] = []
        metadatas: List[Dict[str, Any]] = []
        embeddings: List[List[float]] = []

        for idx, ch in enumerate(tqdm(chunks, desc="写入向量库", unit="块")):
            content = (ch.get("content") or "").strip()
            if not content:
                continue

            meta = {
                "filename": str(ch.get("filename", "unknown")),
                "filepath": str(ch.get("filepath", "")),
                "filetype": str(ch.get("filetype", "")),
                "page_number": int(ch.get("page_number", 0) or 0),
                "chunk_id": int(ch.get("chunk_id", idx) or idx),
            }

            emb = self.get_embedding(content)
            if not emb:
                continue

            fid = hashlib.md5(
                f"{meta['filepath']}::{meta['page_number']}::{meta['chunk_id']}::{idx}".encode(
                    "utf-8"
                )
            ).hexdigest()

            ids.append(fid)
            documents.append(content)
            metadatas.append(meta)
            embeddings.append(emb)

            if len(ids) >= 128:
                self.collection.add(
                    ids=ids,
                    documents=documents,
                    metadatas=metadatas,
                    embeddings=embeddings,
                )
                ids, documents, metadatas, embeddings = [], [], [], []

        if ids:
            self.collection.add(
                ids=ids,
                documents=documents,
                metadatas=metadatas,
                embeddings=embeddings,
            )

        print(f"已添加向量：{self.collection.count()} 条")

    def search(self, query: str, top_k: int = TOP_K) -> List[Dict]:
        """搜索相关文档"""
        emb = self.get_embedding(query)
        if not emb:
            return []

        try:
            res = self.collection.query(
                query_embeddings=[emb],
                n_results=top_k,
                include=["documents", "metadatas", "distances"],
            )
        except Exception as e:
            print(f"搜索失败: {e}")
            return []

        docs = (res.get("documents") or [[]])[0]
        metas = (res.get("metadatas") or [[]])[0]
        dists = (res.get("distances") or [[]])[0]

        out: List[Dict] = []
        for i in range(min(len(docs), top_k)):
            out.append(
                {
                    "content": docs[i],
                    "metadata": metas[i] if i < len(metas) else {},
                    "distance": dists[i] if i < len(dists) else None,
                }
            )
        return out

    def clear_collection(self) -> None:
        """清空collection"""
        try:
            self.chroma_client.delete_collection(name=self.collection_name)
        except Exception:
            pass
        self.collection = self.chroma_client.get_or_create_collection(
            name=self.collection_name, metadata={"description": "课程向量数据库"}
        )
        print("向量数据库已清空")

    def get_collection_count(self) -> int:
        """获取collection中的文档数量"""
        return self.collection.count()
"}

{"path":"/tmp/isolated_workspace_1091/rag_agent.py","content":"from typing import List, Dict, Optional, Tuple

from openai import OpenAI

from config import (
    OPENAI_API_KEY,
    OPENAI_API_BASE,
    MODEL_NAME,
    TOP_K,
)
from vector_store import VectorStore


class RAGAgent:
    def __init__(
        self,
        model: str = MODEL_NAME,
    ):
        self.model = model
        self.client = OpenAI(api_key=OPENAI_API_KEY or None, base_url=OPENAI_API_BASE or None)
        self.vector_store = VectorStore()

        self.system_prompt = (
            "你是课程助教。你的任务是基于检索到的课程材料回答学生问题。\n"
            "回答规则：\n"
            "1. 只能依据提供的课程材料作答，不得凭空编造。\n"
            "2. 若证据不足，请明确说明‘根据当前检索到的材料，无法确定’。\n"
            "3. 回答应尽量清晰、准确、简洁。\n"
            "4. 每个关键结论后都要附上引用，格式为 [文件名#页码]；若是非分页文档块可用 [文件名#chunkX]。\n"
            "5. 如果材料中有多处证据，可综合回答，但不要捏造材料中不存在的内容。"
        )

    def retrieve_context(
        self, query: str, top_k: int = TOP_K
    ) -> Tuple[str, List[Dict]]:
        """检索相关上下文"""
        results = self.vector_store.search(query, top_k=top_k)
        if not results:
            return "", []

        context_parts: List[str] = []
        for idx, item in enumerate(results, 1):
            metadata = item.get("metadata", {}) or {}
            filename = metadata.get("filename", "unknown")
            page_number = int(metadata.get("page_number", 0) or 0)
            chunk_id = int(metadata.get("chunk_id", 0) or 0)
            location = f"第{page_number}页" if page_number > 0 else f"chunk{chunk_id}"
            citation = f"[{filename}#{page_number if page_number > 0 else f'chunk{chunk_id}'}]"
            content = (item.get("content") or "").strip()
            context_parts.append(
                f"资料{idx}：{filename}，位置：{location}，引用：{citation}\n{content}"
            )

        return "\n\n".join(context_parts), results

    def generate_response(
        self,
        query: str,
        context: str,
        chat_history: Optional[List[Dict]] = None,
    ) -> str:
        """生成回答"""
        if not self.model:
            return (
                "未配置可用的大模型，无法生成自然语言回答。\n"
                "不过我已经完成检索。请配置 OPENAI_API_KEY / OPENAI_MODEL 后再试。"
            )

        messages = [{"role": "system", "content": self.system_prompt}]

        if chat_history:
            messages.extend(chat_history)

        user_text = f"""
以下是检索到的课程材料，请基于这些材料回答学生问题。

【课程材料】
{context}

【学生问题】
{query}

请直接给出答案，并确保关键结论附带引用。引用格式必须使用：[文件名#页码] 或 [文件名#chunkX]。
如果现有材料不足以支持回答，请明确说明证据不足。
""".strip()

        messages.append({"role": "user", "content": user_text})

        try:
            response = self.client.chat.completions.create(
                model=self.model, messages=messages, temperature=0.2, max_tokens=1500
            )
            return response.choices[0].message.content
        except Exception as e:
            return f"生成回答时出错: {str(e)}"

    def _fallback_extract_answer(self, query: str, retrieved_docs: List[Dict]) -> str:
        """无 LLM 时的兜底回答：返回相关片段与引用。"""
        if not retrieved_docs:
            return "未检索到相关材料，暂时无法回答。"

        lines = ["当前未配置可用大模型，下面给出最相关的课程材料片段："]
        for item in retrieved_docs[:3]:
            metadata = item.get("metadata", {}) or {}
            filename = metadata.get("filename", "unknown")
            page_number = int(metadata.get("page_number", 0) or 0)
            chunk_id = int(metadata.get("chunk_id", 0) or 0)
            citation = f"[{filename}#{page_number if page_number > 0 else f'chunk{chunk_id}'}]"
            snippet = " ".join((item.get("content") or "").split())[:300]
            lines.append(f"- {snippet} ... {citation}")
        return "\n".join(lines)

    def answer_question(
        self, query: str, chat_history: Optional[List[Dict]] = None, top_k: int = TOP_K
    ) -> str:
        """回答问题"""
        context, retrieved_docs = self.retrieve_context(query, top_k=top_k)

        if not context:
            return "未检索到特别相关的课程材料，无法给出有依据的回答。"

        answer = self.generate_response(query, context, chat_history)
        if answer.startswith("未配置可用的大模型"):
            return self._fallback_extract_answer(query, retrieved_docs)
        return answer

    def chat(self) -> None:
        """交互式对话"""
        print("=" * 60)
        print("欢迎使用智能课程助教系统！输入 exit / quit 退出。")
        print("回答会尽量附带引用。")
        print("=" * 60)

        chat_history = []

        while True:
            try:
                query = input("\n学生: ").strip()

                if not query:
                    continue
                if query.lower() in {"exit", "quit", "q"}:
                    print("\n已退出。")
                    break

                answer = self.answer_question(query, chat_history=chat_history)
                print(f"\n助教: {answer}")

                chat_history.append({"role": "user", "content": query})
                chat_history.append({"role": "assistant", "content": answer})

            except KeyboardInterrupt:
                print("\n\n已退出。")
                break
            except Exception as e:
                print(f"\n错误: {str(e)}")
"}

